#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int **A = (int **)malloc(N * sizeof(int *));
        int **B = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            A[i] = (int *)malloc(N * sizeof(int));
            B[i] = (int *)malloc(N * sizeof(int));
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                scanf("%d", &A[i][j]);
            }
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                scanf("%d", &B[i][j]);
            }
        }
        int possible = 1;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (A[i][j] != B[j][i]) {
                    possible = 0;
                    break;
                }
            }
            if (!possible) break;
        }
        if (possible) printf("Yes\n");
        else printf("No\n");
        for (int i = 0; i < N; i++) {
            free(A[i]);
            free(B[i]);
        }
        free(A);
        free(B);
    }
    return 0;
}

